std::vector<uint8_t> peek_buffer_data(const std::vector<uint8_t>& buffer, size_t bytes_to_peek) {
    // Create a buffer_adaptor object from the input buffer
    hexi::buffer_adaptor<std::vector<uint8_t>> adaptor(const_cast<std::vector<uint8_t>&>(buffer));

    // Check if the requested bytes_to_peek is within the available data in the buffer
    if (bytes_to_peek > buffer.size()) {
        throw std::out_of_range("bytes_to_peek exceeds buffer size");
    }

    // Create a destination vector to hold the peeked data
    std::vector<uint8_t> destination(bytes_to_peek);

    // Use the copy() method of buffer_adaptor to copy data without advancing the read pointer
    adaptor.copy(destination.data(), bytes_to_peek);

    // Return the destination vector containing the peeked data
    return destination;
}
```

