    }

    // Create a destination vector to hold the peeked data
    std::vector<uint8_t> destination(bytes_to_peek);

    // Use the copy() method of buffer_adaptor to copy data without advancing the read pointer
    adaptor.copy(destination.data(), bytes_to_peek);

    // Return the destination vector containing the peeked data
    return destination;
}

